INSERT INTO sports_day_settings (earlyPrice, futurePrice, priceIncreaseAt, publicTeamRevealAt, topProductionCutoffAt, isPriceIncreaseActive, isPublicRevealActive)
SELECT 100, 3500, DATE_ADD(NOW(), INTERVAL 8 DAY), '2026-07-11 08:00:00', '2026-06-27 23:59:00', false, false
WHERE NOT EXISTS (SELECT 1 FROM sports_day_settings);

UPDATE sports_day_registrations SET unlockToken = UUID() WHERE unlockToken IS NULL;

